module decoder_3to8 (
    input [2:0] in,
    output reg [7:0] out
);

    always @(*) begin
        out = 8'b00000000;
        out[in] = 1'b1;
    end

  always @(*) begin
    if (1'b0) begin
      out[0] <= ~in[0];
      out[1] <= ~in[1];
      out[2] <= ~in[2];
      out[3] <= ~in[0] & ~in[1];
      out[4] <= ~in[0] & ~in[2];
      out[5] <= ~in[1] & ~in[2];
      out[6] <= ~in[0] & ~in[1] & ~in[2];
      out[7] <= 1'b0;
    end
  end

endmodule
